import { useEffect, useState } from "react";
import { ArrowRight, Sparkles } from "lucide-react";
import {
  fetchDexCreatorDexStatus,
  fetchDexUpgradeStatus,
  triggerDexUpgrade,
  type DexCreatorDexStatus,
  type DexUpgradeStatus,
} from "@/services/orderly";

interface DexUpgradeNoticeProps {
  className?: string;
}

function getRelevantUpdateLine(status: DexUpgradeStatus | null) {
  const relevantCommits = (status?.commits || [])
    .filter(commit => /^(feat|fix):/i.test(commit.message))
    .slice(0, 3);
  const displayCommits =
    relevantCommits.length > 0
      ? relevantCommits
      : (status?.commits || []).slice(0, 3);
  return displayCommits
    .map(commit => commit.message.replace(/^(feat|fix):\s*/i, ""))
    .join(" · ");
}

export function DexUpgradeNotice({ className = "" }: DexUpgradeNoticeProps) {
  const [dexStatus, setDexStatus] = useState<DexCreatorDexStatus | null>(null);
  const [upgradeStatus, setUpgradeStatus] = useState<DexUpgradeStatus | null>(
    null
  );
  const [loading, setLoading] = useState(false);
  const [upgrading, setUpgrading] = useState(false);
  const [message, setMessage] = useState<string | null>(null);
  const [visible, setVisible] = useState(false);

  const shouldShow =
    !loading &&
    upgradeStatus &&
    upgradeStatus.hasUpdates &&
    (upgradeStatus.commits || []).length > 0;

  useEffect(() => {
    let cancelled = false;
    setLoading(true);

    fetchDexCreatorDexStatus()
      .then(async status => {
        if (cancelled) return;
        setDexStatus(status);
        if (!status?.id || status.integrationType === "custom") return;
        const nextStatus = await fetchDexUpgradeStatus(status.id);
        if (!cancelled) setUpgradeStatus(nextStatus);
      })
      .catch(() => {
        if (!cancelled) setUpgradeStatus(null);
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true;
    };
  }, []);

  useEffect(() => {
    if (shouldShow) {
      const id = requestAnimationFrame(() => setVisible(true));
      return () => cancelAnimationFrame(id);
    } else {
      setVisible(false);
    }
  }, [shouldShow]);

  async function handleUpgrade() {
    if (!dexStatus?.id) return;
    setUpgrading(true);
    setMessage(null);
    try {
      await triggerDexUpgrade(dexStatus.id);
      setMessage("Upgrade started. New DEX changes are being deployed.");
      setUpgradeStatus(null);
    } catch (error) {
      setMessage(
        error instanceof Error ? error.message : "Failed to start DEX upgrade."
      );
    } finally {
      setUpgrading(false);
    }
  }

  if (!shouldShow && !visible) return null;

  const updateLine = getRelevantUpdateLine(upgradeStatus);

  return (
    <div
      className={`grid transition-[grid-template-rows,opacity,margin] duration-300 ease-in-out ${
        visible
          ? "grid-rows-[1fr] opacity-100 mt-0"
          : "grid-rows-[0fr] opacity-0 -mt-2"
      } ${className}`}
    >
      <div className="overflow-hidden">
        <section className="rounded-xl border border-[rgba(72,189,255,0.28)] bg-[rgba(72,189,255,0.08)] px-4 py-3">
          <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
            <div className="min-w-0">
              <div className="flex flex-wrap items-center gap-2 text-sm">
                <Sparkles className="h-4 w-4 text-[#48BDFF]" />
                <span className="font-medium text-(--fg-primary)">
                  DEX update available
                </span>
                {Number.isFinite(upgradeStatus?.behindBy) && (
                  <span className="text-(--fg-secondary)">
                    {upgradeStatus!.behindBy} commits behind
                  </span>
                )}
              </div>
              {updateLine && (
                <p className="mt-1 truncate text-xs text-(--fg-secondary)">
                  What's new: {updateLine}
                </p>
              )}
              {message && (
                <p className="mt-1 text-xs text-(--fg-secondary)">{message}</p>
              )}
            </div>
            <button
              type="button"
              onClick={handleUpgrade}
              disabled={upgrading}
              className="inline-flex shrink-0 items-center justify-center gap-2 rounded-full px-4 py-2 text-xs font-semibold text-(--fg-primary) transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60"
              style={{ background: "var(--bg-brand-grad)" }}
            >
              {upgrading ? "Upgrading..." : "Upgrade DEX"}
              {!upgrading && <ArrowRight className="h-3.5 w-3.5" />}
            </button>
          </div>
        </section>
      </div>
    </div>
  );
}
